import 'package:firebase_auth/firebase_auth.dart'; import 'package:flutter/material.dart'; import 'package:go_router/go_router.dart'; class AuthWrapper extends StatefulWidget { const AuthWrapper({super.key}); @override State<AuthWrapper> createState() => _AuthWrapperState(); } class _AuthWrapperState extends State<AuthWrapper> { @override void initState() { super.initState(); FirebaseAuth.instance.authStateChanges().listen((user) { if (!mounted) return; context.go(user != null ? '/dashboard' : '/login'); }); } @override Widget build(BuildContext context) => const Scaffold(body: Center(child: CircularProgressIndicator())); }